// Unit 1 — First Contact
// Greetings, Zijn & Goodbyes

export default {n:1,lang:"nl",srcLang:"en",track:"v2",title:"First Contact",sub:"Greetings, Zijn & Goodbyes",icon:"👋",level:"A1.1",color:"#7B5EE8",lessons:[
  {id:"v2u1l1",title:"Hallo & Tot ziens",icon:"👋",xp:15,board:true,steps:[
        {type:"intro",title:"Hallo & Tot ziens",desc:"Your very first Dutch words, the ones you'll use every single day. Dutch greetings are logical and quick to master.",goals:["4 greetings (formal + casual)","4 goodbyes","Know when to use each one"]},
        {type:"teach",trg:"hallo",src:"hello",pos:"intj",gender:null,phonetic:"HAH-loh",note:"Works with anyone, anywhere, anytime.\nWhen in doubt: hallo.",example:"A: Hallo! Hoe gaat het?\nB: Goed, dank je! En met jou?\nA: Ook goed!",exampleSrc:"A: Hello! How are you?\nB: Good, thank you! And with you?\nA: Also good!",funFact:"Germanic cousin of English 'hello', German 'Hallo'."},
        {type:"teach",trg:"goedemorgen",src:"good morning",pos:"intj",gender:null,phonetic:"HOO-duh-MOR-hun",note:"COMPOUND: goede (good) + morgen (morning).\nUntil about noon.\nGoede + morgen = good + morning.",example:"A: Goedemorgen, mevrouw!\nB: Goedemorgen! Kan ik u helpen?\nA: Ja, ik zoek de bakker.",exampleSrc:"A: Good morning, ma'am!\nB: Good morning! Can I help you?\nA: Yes, I'm looking for the bakery.",funFact:"Germanic cousin of English 'good morning', German 'Guten Morgen'."},
        {type:"teach",trg:"goedemiddag",src:"good afternoon",pos:"intj",gender:null,phonetic:"HOO-duh-MID-dahg",note:"COMPOUND: goede (good) + middag (midday).\nNoon to ~6 PM. Slightly formal  -  shops, offices.",example:"A: Goedemiddag. Kan ik u helpen?\nB: Ja, ik heb een afspraak.\nA: Komt u binnen!",exampleSrc:"A: Good afternoon. Can I help you?\nB: Yes, I have an appointment.\nA: Come in!",funFact:"Dutch loves building words from parts."},
        {type:"teach",trg:"goedenavond",src:"good evening",pos:"intj",gender:null,phonetic:"HOO-dun-AH-vont",note:"COMPOUND: goede (good) + avond (evening).\nFrom ~6 PM onwards.\nPattern: goede + time of day!",example:"A: Goedenavond allemaal!\nB: Goedenavond! Welkom!\nA: Dank je wel!",exampleSrc:"A: Good evening everyone!\nB: Good evening! Welcome!\nA: Thank you!",funFact:"Dutch loves building words from parts."},
        {type:"tip",title:"🧠 The Goede + Time Pattern",deepDive:{
          title:"The Dutch 'g': the hardest sound",
          text:"You'll hear a distinctive throat sound in 'goedemorgen'. The Dutch 'g' is NOT like English 'g', it's a friction sound from the back of your throat.\n\nTips to practice:\n• Start by saying 'aah' like at the doctor\n• Add friction, like gentle gargling\n• Practice: goed, gaan, groot, groep\n\nIn the south of the Netherlands and Belgium, the 'g' is softer, almost like a gentle 'h'. Both are correct!"
        },text:"All formal greetings follow one formula:\n\ngoede + morgen = goedemorgen (good morning)\ngoede + middag = goedemiddag (good afternoon)\ngoede + avond = goedenavond (good evening)\n\nThree words, one pattern. Done!"},
        {type:"teach",trg:"dag",src:"hello / goodbye",pos:"intj",gender:null,phonetic:"dahg",also:"'de dag' = the day",note:"Works as BOTH hello AND goodbye.\nOften doubled for warmth: 'dag dag!'\n'De dag' = the day (separate meaning).",example:"A: Dag mevrouw! Hoe gaat het?\nB: Dag! Goed, dank je.\nA: Dag dag!",exampleSrc:"A: Hello ma'am! How are you?\nB: Hello! Good, thank you.\nA: Bye bye!",funFact:"Germanic cousin of English 'day', German 'Tag'."},
        {type:"teach",trg:"tot ziens",src:"goodbye (formal)",pos:"intj",gender:null,phonetic:"tot ZEENS",note:"Literally: 'until seeing.'\nFormal  -  shops, offices, strangers.",example:"A: Ik moet gaan. Tot ziens, meneer Bakker.\nB: Tot ziens! Fijne dag nog.\nA: Dank u!",exampleSrc:"A: I have to go. Goodbye, Mr. Bakker.\nB: Goodbye! Have a nice day.\nA: Thank you!",funFact:"Germanic cousin of German 'Auf Wiedersehen'."},
        {type:"teach",trg:"doei",src:"bye! (casual)",pos:"intj",gender:null,phonetic:"DOO-ee",note:"Very casual. Like English 'bye-bye!'\nFriends only.",example:"A: Ik ga naar huis. Doei!\nB: Doei! Tot morgen!\nA: Ja, tot morgen!",exampleSrc:"A: I'm going home. Bye!\nB: Bye! See you tomorrow!\nA: Yes, see you tomorrow!",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"tot later",src:"see you later",pos:"intj",gender:null,phonetic:"tot LAH-tur",note:"'Tot' = until. Dutch builds farewells with it:\ntot morgen = see you tomorrow\ntot zo = see you soon",example:"A: Ik moet gaan. Tot later!\nB: Tot later! Veel plezier.\nA: Dank je!",exampleSrc:"A: I have to go. See you later!\nB: See you later! Have fun.\nA: Thanks!",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"tip",title:"👔 Formal vs Casual",deepDive:{
          title:"Why two levels of politeness?",
          text:"English used to have this too! 'Thou' was informal and 'you' was formal. English dropped 'thou'. Dutch kept both.\n\njij/je = informal 'you' (like old English 'thou')\nu = formal 'you'\n\nThe Netherlands is quite informal compared to Germany or France. Many Dutch people quickly switch to 'je'. But starting with 'u' shows respect.\n\nFun fact: Belgium uses 'u' MUCH more than the Netherlands!"
        },text:"🏢 Formal (shops, strangers, older people):\nGoedemorgen / Goedemiddag / Tot ziens / Dag\n\n😊 Casual (friends, family, peers):\nHallo / Hoi / Hey / Doei\n\nWhen in doubt, start formal. The Dutch will quickly say 'je mag jij zeggen' (you can use informal)."},
        {type:"tip",title:"🗺️ How Dutch Works: A Roadmap",deepDive:{
          title:"Why name these now?",
          text:"Research shows that learners do better when they have a mental roadmap of the language's structure, even before they master each piece.\n\nYou do NOT need to memorize this list! Each system will be formally taught in its own unit with full explanations and practice.\n\nFor now, just know: Dutch is a well-organized language. Every pattern you learn connects to other patterns. The grammar is very regular compared to English, with fewer exceptions.\n\nGood news for English speakers: Dutch is the CLOSEST major language to English. You will recognize many words!"
        },text:"Dutch has a few key systems you will meet throughout this course:\n\n1. Verb conjugation: verbs change by person (stam + ending). Coming in Unit 3.\n2. de/het articles: every noun is 'de' or 'het'. You will start learning these in Lesson 4.\n3. Word order: the verb is ALWAYS second (V2 rule). You just saw this!\n4. Negation: niet (not) and geen (no/none). Coming in Lesson 9.\n5. Separable verbs: some verbs split in two. Coming in Unit 5.\n6. Plurals: -en or -s endings. Unit 4.\n7. Diminutives: -je makes things small/cute. Unit 4.\n8. Adjective agreement: adjectives sometimes add -e. Unit 5."},
        {type:"mc",q:"It's 9 AM. You enter a bakery. You say:",opts:["Goedemorgen","Goedenavond","Goedemiddag","Doei"],ans:"Goedemorgen",hint:"Morning greeting"},
        {type:"mc",q:"Leaving a business meeting, you say:",opts:["Doei!","Tot ziens.","Hoi!","Hey!"],ans:"Tot ziens.",hint:"The formal goodbye"},
        {type:"mc",q:"'Dag' can be used as:",opts:["Only hello","Only goodbye","Both hello AND goodbye","Only formal"],ans:"Both hello AND goodbye",hint:"The Swiss army knife"},
        {type:"fb",opts:["Doei","Meneer","Sorry","Hallo"],hint:"Casual goodbye to a friend",s:"___! Tot morgen!",a:"Doei"},
        {type:"match",pairs:[{trg:"hallo",src:"hello"},{trg:"dag",src:"hello/goodbye"},{trg:"tot ziens",src:"goodbye (formal)"},{trg:"doei",src:"bye! (casual)"}]},
        {type:"mc",q:"What does 'tot ziens' literally mean?",opts:["Good day","Hello again","See you later","Until seeing"],ans:"Until seeing",hint:"Tot = ___"}
  ]},
  {id:"v2u1l2",title:"Zijn: To Be (Complete)",icon:"🧑",xp:20,board:true,steps:[
        {type:"intro",title:"Zijn: To Be",desc:"The most important verb in Dutch. You'll learn ALL forms of 'zijn' in one go, because you need them all from day one.",goals:["All 7 subject pronouns","Every form of zijn","Say 'I am', 'you are', 'we are'..."]},
        {type:"teach",trg:"ik ben",src:"I am",pos:"verb",gender:null,phonetic:"ik ben",note:"'Ik' = I (always lowercase mid-sentence).\nNo article before professions: 'Ik ben student.'",example:"A: Ik ben student.\nB: Veel succes met je studie!\nA: Ja, precies!",exampleSrc:"A: I am a student.\nB: Good luck with your studies!\nA: Yes, exactly!",funFact:"ik + ben: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"jij bent",src:"you are (informal)",pos:"verb",gender:null,phonetic:"yay bent",note:"Use 'jij' with friends, family, peers.\nIn questions: flips to 'ben jij?'  -  the -t drops!",example:"A: Jij bent mijn vriend.\nB: Wat leuk! Hoe oud?\nA: Inderdaad.",exampleSrc:"A: You are my friend.\nB: How nice! How old?\nA: Indeed.",funFact:"jij + bent: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"u bent",src:"you are (formal)",pos:"verb",gender:null,phonetic:"oo bent",note:"For strangers, elders, formal settings.\nSame form as jij: bent.",example:"A: U bent welkom.\nB: Dat klinkt leuk! Mag ik mee?\nA: Klopt!",exampleSrc:"A: You are welcome.\nB: That sounds fun! Can I come along?\nA: Right!",funFact:"u + bent: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"hij is",src:"he is",pos:"verb",gender:null,phonetic:"hay is",note:"'Hij' = he. Uses 'is'. Simple!",example:"A: Hij is groot.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: He is tall.\nB: That's good to know.\nA: Yes, for sure!",funFact:"hij + is: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"zij is",src:"she is",pos:"verb",gender:null,phonetic:"zay is",also:"'zij' also means 'they': context makes it clear",note:"'Zij' = she. Same form as hij: is.",example:"A: Zij is aardig.\nB: Dat klopt.\nA: Precies!",exampleSrc:"A: She is nice.\nB: That's right.\nA: Exactly!",funFact:"zij + is: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"verb_table",title:"Zijn: to be",note:"Only 4 forms to learn: ben, bent, is, zijn.\nThat covers ALL 9 pronouns!",deepDive:{
          title:"The jij/je mystery: what's the difference?",
          text:"You'll see both 'jij' and 'je' everywhere. They mean the same thing!\n\njij = emphasized form\nje = unstressed form\n\nIn daily speech, 'je' is far more common. 'Jij' adds emphasis or contrast:\n• Jij bent groot = YOU are tall (not him)\n• Je bent groot = you're tall (neutral)\n\nSame pattern for all paired pronouns:\n• zij / ze (she or they)\n• wij / we (we)\n\nThe short forms sound more natural in everyday Dutch."
        },groups:[
          {
            label:"Singular",
            rows:[{pronoun:"ik",form:"ben",src:"I am"},{pronoun:"jij / je",form:"bent",src:"you are"},{pronoun:"u",form:"bent",src:"you are (formal)"}]
          },
          {
            label:"Third Person",
            rows:[{pronoun:"hij",form:"is",src:"he is"},{pronoun:"zij / ze",form:"is",src:"she is"},{pronoun:"het",form:"is",src:"it is"}]
          },
          {
            label:"Plural",
            rows:[{pronoun:"wij / we",form:"zijn",src:"we are"},{pronoun:"jullie",form:"zijn",src:"you all are"},{pronoun:"zij / ze",form:"zijn",src:"they are"}]
          }
        ],label:"Full Conjugation"},
        {type:"teach",trg:"wij zijn",src:"we are",pos:"verb",gender:null,phonetic:"vay zayn",note:"'Wij' = we. Uses the full form: 'zijn'.\nShort form: 'we zijn'.",example:"A: Wij zijn blij.\nB: O, dat wist ik niet.\nA: Nu wel!",exampleSrc:"A: We are happy.\nB: Oh, I didn't know that.\nA: Now you do!",funFact:"wij + zijn: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"jullie zijn",src:"you all are",pos:"verb",gender:null,phonetic:"YUL-lee zayn",note:"'Jullie' = you (plural). Also uses 'zijn'.\nNo separate formal plural  -  'u' covers both.",example:"A: Jullie zijn laat!\nB: De tijd gaat snel!\nA: Goed punt.",exampleSrc:"A: You all are late!\nB: Time goes fast!\nA: Good point.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"zij zijn",src:"they are",pos:"verb",gender:null,phonetic:"zay zayn",note:"Same word as 'she'  -  context makes it clear.\nShort form: 'ze zijn'.",example:"A: Zij zijn mijn buren.\nB: Dat klinkt leuk! Mag ik mee?\nA: Goed punt.",exampleSrc:"A: They are my neighbours.\nB: That sounds fun! Can I come along?\nA: Good point.",funFact:"zij + zijn: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"tip",title:"🔑 Pattern: Only 4 Forms",text:"Despite 9 pronouns, zijn only has 4 forms:\n\nben → only ik (I)\nbent → jij (you) and u (you, formal)\nis → hij (he), zij (she), het (it)\nzijn → wij (we), jullie (you all), zij (they)\n\nCompare English: am, are, is, also just 3 forms!\nDutch adds one more (ben ≠ bent) but the logic is identical."},
        {type:"mc",q:"'Wij ___ blij.', Fill in:",opts:["zijn","bent","is","ben"],ans:"zijn",hint:"Which form of '___' fits wij?"},
        {type:"mc",q:"Which pronoun uses 'is'?",opts:["ik","hij","jij","wij"],ans:"hij",hint:"Third person singular"},
        {type:"fb",opts:["zijn","bent","is","ben"],hint:"Plural 'you'",s:"Jullie ___ laat!",a:"zijn"},
        {type:"mc",q:"In a question, 'jij bent' becomes:",opts:["Bent jij?","Is jij?","Ben jij?","Zijn jij?"],ans:"Ben jij?",hint:"Inversion causes the -t to disappear from the verb form"},
        {type:"match",pairs:[{trg:"ik ben",src:"I am"},{trg:"hij is",src:"he is"},{trg:"wij zijn",src:"we are"},{trg:"jij bent",src:"you are"}]},
        {type:"mc",q:"'Zij ___ mijn buren.' (They ___ my neighbours)",opts:["is","bent","ben","zijn"],ans:"zijn",hint:"zij (they) takes the same form as wij"}
  ]},
  {id:"v2u1l3",title:"Wie? Wat? Waar?",icon:"❓",xp:20,board:true,steps:[
        {type:"intro",title:"Question Words",desc:"Six words that unlock hundreds of questions. Plus the one rule you need: Dutch flips the verb in questions.",goals:["6 question words","Question word order","Form real questions"]},
        {type:"teach",trg:"wie",src:"who",pos:"pron",gender:null,phonetic:"vee",note:"Sounds like 'vee'.\nDutch W = English V sound.",example:"A: Wie is dat?\nB: Dat weet ik ook niet zeker.\nA: Ja, precies!",exampleSrc:"A: Who is that?\nB: I'm not sure about that either.\nA: Yes, exactly!",funFact:"Dutch has stressed and unstressed forms for most pronouns. The unstressed form is more common in speech."},
        {type:"teach",trg:"wat",src:"what",pos:"pron",gender:null,phonetic:"vat",also:"also means 'some': wat water = some water",note:"W = V sound. Rhymes with 'but', not 'bat'.\nShort 'a'.",example:"A: Wat is jouw naam?\nB: Goede vraag! Laat me even denken.\nA: Ja, precies!",exampleSrc:"A: What is your name?\nB: Good question! Let me think.\nA: Yes, exactly!",funFact:"Dutch has stressed and unstressed forms for most pronouns. The unstressed form is more common in speech."},
        {type:"teach",trg:"waar",src:"where",pos:"pron",gender:null,phonetic:"vahr",also:"also means 'true': dat is waar! = that's true!",note:"Long 'aa'  -  hold it!\nYou WILL need this word in the Netherlands.",example:"A: Waar is het toilet?\nB: Goede vraag! Laat me even denken.\nA: Klopt!",exampleSrc:"A: Where is the toilet?\nB: Good question! Let me think.\nA: Right!",funFact:"Dutch has stressed and unstressed forms for most pronouns. The unstressed form is more common in speech."},
        {type:"tip",title:"⚡ Question Word Order",deepDive:{
          title:"Why does Dutch flip the verb?",
          text:"This is called 'inversion' and Dutch does it consistently.\n\nIn statements: subject → verb → rest\nJij bent groot. = You are tall.\n\nIn questions: verb → subject → rest\nBen jij groot? = Are you tall?\n\nWith question word: question → verb → subject → rest\nHoe groot ben jij? = How tall are you?\n\nGerman does exactly the same thing! If you ever learn German, this rule transfers directly."
        },text:"Dutch flips the verb before the subject:\n\nJij bent student. → Ben jij student?\n\nWith a question word, it goes FIRST:\nWie ben jij? = Who are you?\nWat is dat? = What is that?\nWaar is het station? = Where is the station?\n\nPattern: ___ ___ → VERB → subject → rest"},
        {type:"teach",trg:"hoe",src:"how",pos:"noun",gender:null,phonetic:"hoo",note:"THE most common way to ask a name.\nLiterally: 'How are-you-called?'",example:"A: Hoe heet je?\nB: Ik zal het voor je uitzoeken.\nA: Goed punt.",exampleSrc:"A: What's your name? (lit: How are you called?)\nB: I'll find out for you.\nA: Good point.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"wanneer",src:"when",pos:"noun",gender:null,phonetic:"vah-NEER",note:"Two syllables: wan-NEER. Stress on second.",example:"A: Wanneer kom je?\nB: Goede vraag! Laat me even denken.\nA: Goed punt.",exampleSrc:"A: When are you coming?\nB: Good question! Let me think.\nA: Good point.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"waarom",src:"why",pos:"noun",gender:null,phonetic:"vahr-OM",note:"Waar + om = 'where about.'\nStress on second: vahr-OM.",example:"A: Waarom niet?\nB: Goede vraag! Laat me even denken.\nA: Goed punt.",exampleSrc:"A: Why not?\nB: Good question! Let me think.\nA: Good point.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"tip",title:"🗣️ Your Survival Questions",text:"Memorize these 5, they'll save you daily:\n\nWat is dat? = What is that?\nWaar is het toilet? = Where is the toilet?\nHoe heet je? = What's your name?\nWanneer vertrekt de trein? = When does the train leave?\nWaarom niet? = Why not?\n\nNotice: verb ALWAYS comes right after the question word."},
        {type:"mc",q:"'Waar is het station?' means:",opts:["Where is the station?","Who is at the station?","What is the station?","How is the station?"],ans:"Where is the station?",hint:"Waar = w..."},
        {type:"mc",q:"'Hoe heet je?' literally means:",opts:["What is your name?","How are you called?","Where are you from?","Who are you?"],ans:"How are you called?",hint:"Hoe = how"},
        {type:"fb",opts:["Wie","Wat","Waar","Hoe"],hint:"Asking about a person",s:"___ is dat?",a:"Wie"},
        {type:"mc",q:"In Dutch questions, the verb comes:",opts:["At the end","After everything","Right after the question word","Before the question word"],ans:"Right after the question word",hint:"___ ___ → VERB → subject"},
        {type:"match",pairs:[{trg:"wie",src:"who"},{trg:"wat",src:"what"},{trg:"waar",src:"where"},{trg:"waarom",src:"why"}]},
        {type:"mc",q:"'Wanneer kom je?' means:",opts:["Where are you going?","How are you coming?","Why are you coming?","When are you coming?"],ans:"When are you coming?",hint:"Wanneer = when"}
  ]},
  {id:"v2u1l4",title:"De, Het & Een",icon:"📦",xp:20,board:true,steps:[
        {type:"intro",title:"De, Het & Een: Dutch Articles",desc:"Dutch has TWO words for 'the': de and het. No reliable rule  -  you learn them with each word.",goals:["Know de vs het","Use een (a/an)","Learn 6 nouns with their articles","Accept: memorize, don't overthink"]},
        {type:"teach",trg:"de man",src:"the man",pos:"noun",gender:"c",phonetic:"duh mahn",also:"'man' also means 'husband'",note:"'De' is the most common article (~2/3 of nouns).\nAll plurals ALWAYS use 'de'.",example:"A: De man is groot.\nB: Dat klinkt als een leuke familie.\nA: Klopt!",exampleSrc:"A: The man is tall.\nB: That sounds like a nice family.\nA: Right!",funFact:"Germanic cousin of English 'man', German 'Mann'."},
        {type:"teach",trg:"de vrouw",src:"the woman",pos:"noun",gender:"c",phonetic:"duh vrouw",also:"'vrouw' also means 'wife'",note:"A de-word. 'v' = English 'v'.\n'ouw' rhymes with 'now'.",example:"A: De vrouw is aardig.\nB: Dat klinkt als een leuke familie.\nA: Goed punt.",exampleSrc:"A: The woman is nice.\nB: That sounds like a nice family.\nA: Good point.",funFact:"Germanic cousin of German 'Frau'."},
        {type:"teach",trg:"het kind",src:"the child",pos:"noun",gender:"n",phonetic:"hut kint",note:"'Het' words are ~1/3 of all nouns.\nNo reliable rule  -  learn it per word.",example:"A: Het kind speelt buiten.\nB: Dat klinkt als een leuke familie.\nA: Ja, precies!",exampleSrc:"A: The child plays outside.\nB: That sounds like a nice family.\nA: Yes, exactly!",funFact:"Germanic cousin of German 'Kind'."},
        {type:"tip",title:"📖 De vs Het: The Honest Truth",deepDive:{
          title:"Why does Dutch have de and het?",
          text:"Dutch inherited two grammatical genders from older Germanic:\n\nde-words = originally masculine OR feminine\nhet-words = neuter\n\nOver centuries, Dutch merged masculine and feminine into one group ('de') but kept neuter separate ('het'). German still has all three (der/die/das). Dutch simplified to two.\n\nFun fact: Dutch speakers themselves often disagree about de/het for some words! Even native speakers sometimes say 'de auto' and 'het auto' interchangeably. So don't stress too much!"
        },text:"There is NO reliable rule for de vs het.\n\n✅ What helps:\n• Learn each noun WITH its article (de man, het huis)\n• All plurals use 'de' (de mannen, de huizen)\n• Most people-words use 'de'\n• Words ending in -je always use 'het'\n• If you guess 'de', you're right ~65% of the time"},
        {type:"teach",trg:"het huis",src:"the house",pos:"noun",gender:"n",phonetic:"hut howss",note:"The 'ui' is a uniquely Dutch sound  -  round your lips!\nDoesn't exist in English.",example:"A: Het huis is mooi.\nB: Wat een mooi huis!\nA: Dat is zo.",exampleSrc:"A: The house is beautiful.\nB: What a nice house!\nA: That's true.",funFact:"Germanic cousin of English 'house', German 'Haus'."},
        {type:"teach",trg:"een boek",src:"a book",pos:"noun",gender:null,phonetic:"un book",note:"'Een' = a/an for ALL nouns.\nIt NEVER changes. That's the good news!",example:"A: Ik lees een boek.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: I'm reading a book.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of English 'book', German 'Buch'."},
        {type:"teach",trg:"de kat",src:"the cat",pos:"noun",gender:"c",phonetic:"duh kaht",note:"A de-word. Most animals use 'de'.\nException: 'het paard' (the horse).",example:"A: De kat slaapt.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: The cat sleeps.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of English 'cat', German 'Katze'."},
        {type:"mc",q:"Which article goes with 'huis'?",opts:["het","de","een","geen"],ans:"het",hint:"Think back to the teach cards for house"},
        {type:"mc",q:"All plural nouns use:",opts:["het","de","een","No article"],ans:"de",hint:"De mannen, de huizen, de katten..."},
        {type:"fb",opts:["De","Het","Een","Geen"],hint:"Remember which article 'vrouw' used in the teach card",s:"___ vrouw is aardig.",a:"De"},
        {type:"mc",q:"'Een' is used for:",opts:["Only de-words","Only het-words","Both de and het words","Plural nouns"],ans:"Both de and het words",hint:"Een never changes!"},
        {type:"match",pairs:[{trg:"de man",src:"the man"},{trg:"het huis",src:"the house"},{trg:"de kat",src:"the cat"},{trg:"het kind",src:"the child"}]},
        {type:"mc",q:"Words ending in -je (like broodje, meisje) always use:",opts:["de","geen","een","het"],ans:"het",hint:"All diminutives share the same article, regardless of the base noun"}
  ]},
  {id:"v2u1l5",title:"Hebben: To Have (Complete)",icon:"✋",xp:20,board:true,steps:[
        {type:"intro",title:"Hebben: To Have",desc:"Your second essential verb, all forms at once. After this lesson you know zijn AND hebben, the two verbs that power 60% of daily Dutch.",goals:["Every form of hebben","The -t drop rule in questions","Mini review of L1–L4"]},
        {type:"teach",trg:"ik heb",src:"I have",pos:"verb",gender:null,phonetic:"ik hep",note:"Spelled 'heb', sounds like 'hep'.\nFinal b → p, d → t, g → k in Dutch!",example:"A: Ik heb een kat.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: I have a cat.\nB: That's good to know.\nA: Yes, for sure!",funFact:"ik + heb: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"jij hebt",src:"you have (informal)",pos:"verb",gender:null,phonetic:"yay hept",note:"'Hebt' for jij.\nIn questions: 'Heb jij...?'  -  the -t drops!\nReal rule, not an exception.",example:"A: Jij hebt een mooie kat!\nB: Dank je! Ze is heel lief.\nA: Hoe heet ze?",exampleSrc:"A: You have a beautiful cat!\nB: Thanks! She is very sweet.\nA: What is her name?",funFact:"jij + hebt: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"u heeft",src:"you have (formal)",pos:"verb",gender:null,phonetic:"oo hayft",note:"Some say 'u hebt'  -  both accepted.\n'U heeft' is more standard.",example:"A: U heeft een afspraak om drie uur.\nB: Ja, dat klopt.\nA: Komt u maar binnen.",exampleSrc:"A: You have an appointment at three o'clock.\nB: Yes, that's correct.\nA: Please come in.",funFact:"u + heeft: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"hij heeft",src:"he/she has",pos:"verb",gender:null,phonetic:"hay hayft",note:"Three forms: heb, hebt, heeft.\nik → no -t, jij → -t, hij → -ft.",example:"A: Heeft hij een hond?\nB: Ja, hij heeft een grote hond.\nA: Hoe heet de hond?",exampleSrc:"A: Does he have a dog?\nB: Yes, he has a big dog.\nA: What's the dog's name?",funFact:"hij + heeft: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"verb_table",title:"Hebben: to have",note:"4 forms: heb, hebt, heeft, hebben.\nSame pattern as zijn!",deepDive:{
          title:"The -t drop rule: the most useful grammar trick",
          text:"When jij comes AFTER the verb (in questions), the -t disappears:\n\nJij hebt een auto. = You have a car.\nHeb jij een auto? = Do you have a car?\n\nJij bent groot. = You are tall.\nBen jij groot? = Are you tall?\n\nJij werkt hier. = You work here.\nWerk jij hier? = Do you work here?\n\nThis ONLY happens with jij/je, never with u, hij, or anyone else. It's one of the first 'real' grammar rules worth mastering."
        },groups:[
          {
            label:"Singular",
            rows:[{pronoun:"ik",form:"heb",src:"I have"},{pronoun:"jij / je",form:"hebt",src:"you have"},{pronoun:"u",form:"heeft",src:"you have (formal)"}]
          },
          {
            label:"Third Person",
            rows:[{pronoun:"hij",form:"heeft",src:"he has"},{pronoun:"zij / ze",form:"heeft",src:"she has"},{pronoun:"het",form:"heeft",src:"it has"}]
          },
          {
            label:"Plural",
            rows:[{pronoun:"wij / we",form:"hebben",src:"we have"},{pronoun:"jullie",form:"hebben",src:"you all have"},{pronoun:"zij / ze",form:"hebben",src:"they have"}]
          }
        ],label:"Full Conjugation"},
        {type:"teach",trg:"wij hebben",src:"we have",pos:"verb",gender:null,phonetic:"vay HEB-bun",also:"'honger hebben' = to be hungry (lit: to have hunger)",note:"Dutch says 'have hunger' not 'are hungry'.\nSame for thirst: 'Ik heb dorst.'\nLike French and German!",example:"A: Wij hebben honger!\nB: Ik ook. Zullen we eten?\nA: Ja, graag!",exampleSrc:"A: We are hungry!\nB: Me too. Shall we eat?\nA: Yes, please!",funFact:"Connected to German through their shared West Germanic ancestry."},
        {type:"teach",trg:"zij hebben",src:"they have",pos:"verb",gender:null,phonetic:"zay HEB-bun",note:"Same as wij: hebben.\nThe plural always uses the full form.",example:"A: Zij hebben een groot huis.\nB: Echt? Waar wonen zij?\nA: In Amsterdam.",exampleSrc:"A: They have a big house.\nB: Really? Where do they live?\nA: In Amsterdam.",funFact:"zij + hebben: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"tip",title:"🔁 Quick Review: Zijn + Hebben",text:"ZIJN (to be): ben, bent, is, zijn\nHEBBEN (to have): heb, hebt, heeft, hebben\n\n• Ik ben student. = I am a student.\n• Ik heb een kat. = I have a cat.\n• Ben jij blij? = Are you happy?\n• Hij is groot. = He is tall."},
        {type:"mc",q:"'Ik heb een boek' means:",opts:["I have a book","I am a book","I want a book","I see a book"],ans:"I have a book",hint:"Heb = have"},
        {type:"mc",q:"In a question, 'jij hebt' becomes:",opts:["Hebt jij?","Heb jij?","Heeft jij?","Hebben jij?"],ans:"Heb jij?",hint:"Inversion causes the -t to disappear from the verb form"},
        {type:"mc",q:"'Wij hebben honger' means:",opts:["We are home","We have a dog","We are hungry","We have money"],ans:"We are hungry",hint:"Dutch says 'have hunger' not 'are h...'"},
        {type:"fb",opts:["heeft","hebt","heb","hebben"],hint:"hij/zij uses which form?",s:"Hij ___ een kat.",a:"heeft"},
        {type:"mc",q:"How do you say 'goodbye' formally?",opts:["Doei","Hallo","Dag dag","Tot ziens"],ans:"Tot ziens",hint:"From Lesson 1"},
        {type:"mc",q:"'Waar is het station?', 'waar' means:",opts:["where","who","what","when"],ans:"where",hint:"From Lesson 3"},
        {type:"match",pairs:[{trg:"ik heb",src:"I have"},{trg:"wij hebben",src:"we have"},{trg:"hij heeft",src:"he has"},{trg:"jij hebt",src:"you have"}]}
  ]},
  {id:"v2u1l6",title:"Ja, Nee & Alsjeblieft",icon:"🙏",xp:20,board:true,steps:[
        {type:"intro",title:"Ja, Nee & Alsjeblieft",desc:"The three magic words of Dutch politeness. Master these and every interaction gets smoother, shops, cafés, trains, everywhere.",goals:["Ja / nee / misschien","Alsjeblieft & alstublieft","Dank je & dank u","Polite social glue phrases"]},
        {type:"teach",trg:"ja",src:"yes",pos:"intj",gender:null,phonetic:"yah",note:"J in Dutch ALWAYS sounds like English Y.\n'Ja, graag' = yes please  -  your go-to in shops.",example:"A: Wil je koffie?\nB: Ja, graag!\nA: Met melk?",exampleSrc:"A: Do you want coffee?\nB: Yes, please!\nA: With milk?",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"nee",src:"no",pos:"intj",gender:null,phonetic:"nay",note:"Long 'ee' sound.\nAlways 'Nee, dank je'  -  never just 'nee' (too abrupt).",example:"A: Wil je suiker?\nB: Nee, dank je.\nA: Goed, hier is je koffie.",exampleSrc:"A: Do you want sugar?\nB: No, thank you.\nA: Good, here is your coffee.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"misschien",src:"maybe / perhaps",pos:"verb",gender:null,phonetic:"mis-SKEEN",note:"Literally 'it may seem.' Stress: mis-SCHIEN.\n'sch' = 'sk' sound.",example:"A: Ga je mee naar het park?\nB: Misschien. Hoe laat?\nA: Om drie uur.",exampleSrc:"A: Are you coming to the park?\nB: Maybe. What time?\nA: At three o'clock.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"tip",title:"🙏 Alsjeblieft: The Swiss Army Word",deepDive:{
          title:"How 'alsjeblieft' is a compressed sentence",
          text:"It looks like one word but it's actually a full sentence!\n\nals + je + belieft = 'if it pleases you'\n\n• als = if\n• je = you (informal)\n• belieft = pleases (archaic Dutch verb)\n\nThe formal version 'alstublieft' works the same way:\nals + t + u + belieft = 'if it pleases you' (formal)\n\nThe 't' comes from the formal verb conjugation. Most Dutch people don't realize this, you'll impress them if you know it!"
        },text:"'Alsjeblieft' is used THREE ways:\n\n1. As 'please':\nMag ik een koffie, alsjeblieft? = Can I have a coffee, please?\n\n2. As 'here you go' (handing something):\nAlsjeblieft! = Here you go!\n\n3. As 'you're welcome':\nDank je! → Alsjeblieft! = Thanks! → You're welcome!\n\nOne word, three functions. Context makes it clear."},
        {type:"teach",trg:"alsjeblieft",src:"please / here you go (informal)",pos:"intj",gender:null,phonetic:"AHL-shuh-BLEEFT",note:"COMPOUND: als (if) + je (you) + belieft (please).\nLiterally 'if it pleases you' (als + je + belieft).\nAlso means 'here you go' when handing something over.",example:"A: Een koffie, alsjeblieft.\nB: Alsjeblieft! Met melk?\nA: Nee, dank je.",exampleSrc:"A: A coffee, please.\nB: Here you go! With milk?\nA: No, thank you.",funFact:"Dutch loves building words from parts."},
        {type:"teach",trg:"alstublieft",src:"please / here you go (formal)",pos:"intj",gender:null,phonetic:"AHL-stoo-BLEEFT",note:"COMPOUND: als (if) + het u (it you) + belieft (please).\nFormal version: als + u + belieft.\nThe je/u swap is the only difference.",example:"A: Uw koffie, alstublieft.\nB: Dank u wel!\nA: Graag gedaan.",exampleSrc:"A: Your coffee, here you go.\nB: Thank you very much!\nA: You're welcome.",funFact:"Dutch loves building words from parts."},
        {type:"teach",trg:"dank je",src:"thank you (informal)",pos:"intj",gender:null,phonetic:"dahnk yuh",note:"Add 'wel' for emphasis: 'dank je wel!'\nYou'll hear 'dankjewel' as one word.",example:"A: Hier is je boek.\nB: Dank je wel!\nA: Graag gedaan!",exampleSrc:"A: Here is your book.\nB: Thank you very much!\nA: You're welcome!",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"dank u",src:"thank you (formal)",pos:"intj",gender:null,phonetic:"dahnk oo",note:"je → u is the formality switch.\n'Dank u wel' for emphasis.\nAlso common: 'bedankt' (works for both).",example:"A: Uw tas, meneer.\nB: Dank u wel, mevrouw.\nA: Alstublieft!",exampleSrc:"A: Your bag, sir.\nB: Thank you very much, ma'am.\nA: You're welcome!",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"tip",title:"🔑 The je/u Pattern",text:"• alsjeblieft / alstublieft = please\n• dank je / dank u = thank you\n• hoe heet je / hoe heet u = what's your name\n• hoe gaat het met je / met u = how are you\n\n'je' ↔ 'u' is the ONLY switch. Works for ANY phrase."},
        {type:"teach",trg:"sorry",src:"sorry",pos:"intj",gender:null,phonetic:"SOR-ee",note:"Borrowed from English  -  same meaning.\n'Pardon' also works (slightly more formal).",example:"A: Sorry, waar is het station?\nB: Het station is daar, links.\nA: Dank je!",exampleSrc:"A: Sorry, where is the station?\nB: The station is there, on the left.\nA: Thanks!",funFact:"A borrowed word — related to English 'sorry'."},
        {type:"teach",trg:"graag",src:"gladly / please",pos:"adv",gender:null,phonetic:"hrahg",also:"'ik wil graag' = I would like",note:"Incredibly versatile:\nja, graag = yes please\ngraag gedaan = you're welcome\nik wil graag... = I would like...",example:"A: Dank je voor de hulp!\nB: Graag gedaan!\nA: Je bent heel aardig.",exampleSrc:"A: Thanks for the help!\nB: You're welcome!\nA: You are very kind.",funFact:"Common in everyday Dutch. Position in the sentence follows the V2 rule: verb stays second."},
        {type:"mc",q:"A waiter hands you coffee. You say:",opts:["Dank je wel","Alsjeblieft","Sorry","Graag"],ans:"Dank je wel",hint:"They gave you something: you thank them"},
        {type:"mc",q:"You hand a friend their book back. You say:",opts:["Dank je","Alsjeblieft","Sorry","Nee"],ans:"Alsjeblieft",hint:"You're handing something over"},
        {type:"fb",opts:["alsjeblieft","sorry","dank je","graag"],hint:"Ordering politely",s:"Een koffie, ___.",a:["alsjeblieft","alstublieft"]},
        {type:"mc",q:"The formal version of 'dank je' is:",opts:["Dank hij","Dank wij","Dank u","Dank ze"],ans:"Dank u",hint:"je ↔ u is the switch"},
        {type:"match",pairs:[{trg:"ja, graag",src:"yes, please"},{trg:"nee, dank je",src:"no, thank you"},{trg:"alsjeblieft",src:"please / here you go"},{trg:"sorry",src:"sorry"}]},
        {type:"mc",q:"'Graag gedaan' means:",opts:["Sorry about that","See you later","Yes please","You're welcome"],ans:"You're welcome",hint:"Literally: gladly done"}
  ]},
  {id:"v2u1l7",title:"Numbers 1–10",icon:"🔢",xp:20,board:true,steps:[
        {type:"intro",title:"Numbers 1–10",desc:"Dutch numbers 1–10 are your everyday toolkit, prices, times, addresses, phone numbers. Most are recognizable if you speak English or German.",goals:["Count 1–10 in Dutch","Recognize numbers in context","Spot the Germanic cousins"]},
        {type:"teach",trg:"een",src:"one",pos:"num",gender:null,phonetic:"ayn",note:"As number: stressed 'EEN koffie.'\nAs article (a/an): unstressed 'een koffie.'\nIn writing: 'één' (with accents) = the number.",example:"Een koffie, alsjeblieft.",exampleSrc:"One coffee, please.",deepDive:"Dutch uses accent marks to tell them apart:\n\néén = the number one (één koffie = one coffee)\neen = the article a/an (een koffie = a coffee)\n\nIn speech, stress does the job.\nIn writing, the accents do.\nYou'll see 'één' on menus, signs, and clocks.",funFact:"Dutch numbers follow Germanic patterns. After 20, the ones come before the tens (like German)."},
        {type:"teach",trg:"twee",src:"two",pos:"noun",gender:null,phonetic:"tvay",note:"'tw' sounds like English 'tv'.\nLips together, then release.",example:"Twee broodjes.",exampleSrc:"Two sandwiches.",funFact:"Germanic cousin of English 'two', German 'zwei'."},
        {type:"teach",trg:"drie",src:"three",pos:"noun",gender:null,phonetic:"dree",note:"Like English 'three' without the 'th'.\nDutch 'r' is slightly rolled.",example:"Drie kinderen.",exampleSrc:"Three children.",funFact:"Germanic cousin of English 'three', German 'drei'."},
        {type:"teach",trg:"vier",src:"four",pos:"noun",gender:null,phonetic:"feer",note:"Sounds like 'fear.' Dutch v = English f:\nvier/four, vader/father, vis/fish.",example:"Vier seizoenen.",exampleSrc:"Four seasons.",funFact:"Germanic cousin of German 'vier', English 'four'."},
        {type:"teach",trg:"vijf",src:"five",pos:"noun",gender:null,phonetic:"vayf",note:"'ij' = uniquely Dutch, like 'ay' in 'say'.\nRhymes with English 'knife'.",example:"Vijf euro.",exampleSrc:"Five euros.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"tip",title:"🧠 Germanic Cousins",text:"Dutch numbers are siblings of English and German:\n\n• een = one (German: eins)\n• twee = two (German: zwei)\n• drie = three (German: drei)\n• vier = four (German: vier)\n• vijf = five (German: fünf)\n\nYou already know these, your brain just needs to connect the dots!"},
        {type:"teach",trg:"zes",src:"six",pos:"noun",gender:null,phonetic:"zes",note:"Almost identical to English 'says'. Easy!",example:"Zes appels.",exampleSrc:"Six apples.",funFact:"Germanic cousin of English 'six', German 'sechs'."},
        {type:"teach",trg:"zeven",src:"seven",pos:"verb",gender:null,phonetic:"ZAY-vun",note:"Dutch 'v' = English 'v'.\nCompare: seven / zeven / sieben.",example:"Zeven dagen.",exampleSrc:"Seven days.",funFact:"Germanic cousin of English 'seven', German 'sieben'."},
        {type:"teach",trg:"acht",src:"eight",pos:"noun",gender:null,phonetic:"ahgt",note:"'ch' = same throat sound as Dutch 'g'.",example:"Acht uur.",exampleSrc:"Eight o'clock.",funFact:"Germanic cousin of English 'eight', German 'acht'."},
        {type:"teach",trg:"negen",src:"nine",pos:"verb",gender:null,phonetic:"NAY-gun",note:"The 'g' has the Dutch throat sound.",example:"Negen maanden.",exampleSrc:"Nine months.",funFact:"Germanic cousin of English 'nine', German 'neun'."},
        {type:"teach",trg:"tien",src:"ten",pos:"verb",gender:null,phonetic:"teen",note:"Sounds like English 'teen'.",example:"Tien minuten.",exampleSrc:"Ten minutes.",funFact:"Germanic cousin of English 'ten', German 'zehn'."},
        {type:"tip",title:"💰 Numbers in Real Life",text:"You'll use these instantly:\n\nDat is drie euro vijftig. = That's €3.50.\nTwee koffie, alsjeblieft. = Two coffees, please.\nHet is vijf uur. = It's five o'clock.\nNummer acht. = Number eight.\n\nDutch people use numbers constantly!"},
        {type:"mc",q:"How do you say 'five' in Dutch?",opts:["vijf","vier","zes","drie"],ans:"vijf",hint:"Contains the 'ij' diphthong"},
        {type:"mc",q:"'Acht uur' means:",opts:["Six o'clock","Eight o'clock","Ten o'clock","Four o'clock"],ans:"Eight o'clock",hint:"Acht = e..."},
        {type:"fb",opts:["Twee","Tien","Zes","Vijf"],hint:"Count in order",s:"Eén, ___, drie, vier...",a:"Twee"},
        {type:"mc",q:"Which number sounds like English 'fear'?",opts:["vijf","drie","vier","zes"],ans:"vier",hint:"Sounds like English 'fear' without the R"},
        {type:"match",pairs:[{trg:"drie",src:"three"},{trg:"zeven",src:"seven"},{trg:"negen",src:"nine"},{trg:"tien",src:"ten"}]},
        {type:"mc",q:"'Een' as a number is pronounced differently than 'een' as:",opts:["a verb","a name","an adjective","an article (a/an)"],ans:"an article (a/an)",hint:"Number = stressed, ___ = unstressed"}
  ]},
  {id:"v2u1l8",title:"Introducing Yourself",icon:"🙋",xp:20,board:true,steps:[
        {type:"intro",title:"Introducing Yourself",desc:"Put it all together, you'll learn to introduce yourself in Dutch with a natural mini-conversation. This is where L1–L7 click into place.",goals:["Say your name","Say where you're from","Ask someone's name","Have a real mini-conversation"]},
        {type:"teach",trg:"ik heet...",src:"my name is... (lit: I am called)",pos:"verb",gender:null,phonetic:"ik hayt",note:"'Heten' = to be called.\nMore natural than 'mijn naam is'.",example:"A: Hoe heet je?\nB: Ik heet Anna. En jij?\nA: Ik heet Mark. Aangenaam!",exampleSrc:"A: What's your name?\nB: My name is Anna. And you?\nA: My name is Mark. Nice to meet you!",funFact:"ik + heet...: Dutch verb conjugation follows regular patterns once you learn the stem."},
        {type:"teach",trg:"hoe heet je?",src:"what's your name? (informal)",pos:"verb",gender:null,phonetic:"hoo hayt yuh",note:"Literally: 'How are-you-called?'\n'hoe' = how, not what. Verb flips in questions.",example:"A: Hoi! Hoe heet je?\nB: Ik heet Sophie.\nA: Leuk! Ik heet Jan.",exampleSrc:"A: Hi! What's your name?\nB: My name is Sophie.\nA: Nice! My name is Jan.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"aangenaam",src:"nice to meet you",pos:"intj",gender:null,phonetic:"AHN-guh-nahm",also:"literally means 'pleasant' or 'agreeable'",note:"Slightly formal but universally appropriate.\nLiterally: 'pleasant'.",example:"A: Ik heet Peter. Aangenaam!\nB: Aangenaam! Ik heet Lisa.\nA: Leuk je te ontmoeten.",exampleSrc:"A: My name is Peter. Nice to meet you!\nB: Nice to meet you! My name is Lisa.\nA: Nice to meet you.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"en",src:"and",pos:"conj",gender:null,phonetic:"en",note:"The glue word of Dutch.\n'En jij?' = and you?  -  bounces any question back.",example:"A: Ik heet Sophie. En jij?\nB: Ik heet Mark.\nA: Leuk! En waar woon je?",exampleSrc:"A: My name is Sophie. And you?\nB: My name is Mark.\nA: Nice! And where do you live?",funFact:"Word order matters: some conjunctions keep normal order, others push the verb to the end."},
        {type:"teach",trg:"maar",src:"but",pos:"conj",gender:null,phonetic:"mahr",note:"The second connector you need.\n'En' links, 'maar' contrasts.\n'Ik ben klein maar sterk.' = I am small but strong.",example:"A: Spreek je Nederlands?\nB: Een beetje, maar ik leer nog.\nA: Je doet het goed!",exampleSrc:"A: Do you speak Dutch?\nB: A little, but I'm still learning.\nA: You're doing well!",funFact:"Germanic cousin of German 'aber', English 'more (archaic: 'no more')'."},
        {type:"tip",title:"🗣️ Your First Dutch Conversation",deepDive:{
          title:"'En jij?': the power of bouncing back",
          text:"In any language, the fastest way to keep a conversation going is to bounce the question back:\n\nHoe heet je? = What's your name?\nIk heet... En jij? = I'm called... And you?\n\nHoe gaat het? = How are you?\nGoed! En met jou? = Good! And with you?\n\nWaar woon je? = Where do you live?\nIk woon in... En jij? = I live in... And you?\n\n'En jij?' (and you?) and 'en met jou?' (and with you?) are your conversation lifelines.\n\nNote: 'jou' is the object form of 'jij', like English 'me' vs 'I'. More on this in Unit 2!"
        },text:"A: Hallo! Hoe heet je? = Hi! What's your name?\nB: Ik heet Sophie. En jij? = I'm Sophie. And you?\nA: Ik heet Jan. Aangenaam! = I'm Jan. Nice to meet you!\nB: Aangenaam! = Nice to meet you!\n\nThat's it, you just introduced yourself in Dutch!"},
        {type:"teach",trg:"ik kom uit...",src:"I come from...",pos:"verb",gender:null,phonetic:"ik kom owt",note:"'Uit' = from/out of.\nThe 'ui' is that Dutch diphthong again!",example:"A: Waar kom je vandaan?\nB: Ik kom uit Nederland.\nA: Leuk! En ik kom uit België.",exampleSrc:"A: Where are you from?\nB: I come from the Netherlands.\nA: Nice! And I come from Belgium.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"waar kom je vandaan?",src:"where are you from?",pos:"intj",gender:null,phonetic:"vahr kom yuh fan-DAHN",note:"'Vandaan' = from-there.\n'Waar kom je uit?' also works, but 'vandaan' is more natural.",example:"A: Waar kom je vandaan?\nB: Uit Duitsland. En jij?\nA: Ik kom uit Frankrijk.",exampleSrc:"A: Where are you from?\nB: From Germany. And you?\nA: I come from France.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"teach",trg:"ik woon in...",src:"I live in...",pos:"verb",gender:null,phonetic:"ik vohn in",note:"'Wonen' = to live (reside).\nW = V sound. 'Woon' rhymes with 'bone'.",example:"A: Waar woon je?\nB: Ik woon in Amsterdam.\nA: Wat leuk! Ik ook.",exampleSrc:"A: Where do you live?\nB: I live in Amsterdam.\nA: How nice! Me too.",funFact:"Germanic cousin of German 'Ich wohne in...'."},
        {type:"teach",trg:"ik spreek een beetje Nederlands",src:"I speak a little Dutch",pos:"verb",gender:null,phonetic:"ik sprayk un BAYT-yuh NAY-dur-lahnts",note:"THE survival sentence. Dutch people love hearing this!\n'Een beetje' = a little bit.",example:"A: Spreek je Nederlands?\nB: Ik spreek een beetje Nederlands.\nA: Heel goed! Je doet het prima.",exampleSrc:"A: Do you speak Dutch?\nB: I speak a little Dutch.\nA: Very good! You're doing great.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"tip",title:"🎬 The Full Introduction",deepDive:{
          title:"Model conversation",
          text:"A: Hallo! Ik heet Jan. Hoe heet jij?\n→ Hi! I'm Jan. What's your name?\n\nB: Ik heet Sophie. Aangenaam!\n→ I'm Sophie. Nice to meet you!\n\nA: Waar kom je vandaan?\n→ Where are you from?\n\nB: Ik kom uit België. En jij?\n→ I'm from Belgium. And you?\n\nA: Ik kom uit Nederland. Ik woon in Utrecht.\n→ I'm from the Netherlands. I live in Utrecht.\n\nB: Leuk! Ik woon in Antwerpen.\n→ Nice! I live in Antwerp.\n\nYou know every word here. You are ready."
        },text:"You know every word you need for a natural Dutch introduction: name, origin, residence. Tap below to see a full model conversation."},
        {type:"mc",q:"Someone asks 'Hoe heet je?', you reply:",opts:["Ik heet...","Ik kom uit...","Ik woon in...","Ik ben..."],ans:"Ik heet...",hint:"They asked your name"},
        {type:"mc",q:"'Waar kom je vandaan?' asks about your:",opts:["Your full name","Your origin","Your profession","Your family"],ans:"Your origin",hint:"Waar = where, vandaan = from"},
        {type:"fb",opts:["spreek","heet","woon","kom"],hint:"What do you do with a language?",s:"Ik ___ een beetje Nederlands.",a:"spreek"},
        {type:"mc",q:"'En jij?' is used to:",opts:["End a conversation","Ask someone to repeat","Bounce the question back","Say goodbye"],ans:"Bounce the question back",hint:"How to ask 'and you?' ___"},
        {type:"match",pairs:[{trg:"ik heet",src:"my name is"},{trg:"ik kom uit",src:"I come from"},{trg:"ik woon in",src:"I live in"},{trg:"aangenaam",src:"nice to meet you"}]},
        {type:"mc",q:"Dutch people react to 'ik spreek een beetje Nederlands' by:",opts:["Being offended","Correcting your grammar","Ignoring you","Appreciating the effort"],ans:"Appreciating the effort",hint:"They love it when foreigners try!"}
  ]},
  {id:"v2u1l9",title:"Niet & Geen: Saying No",icon:"🚫",xp:20,board:true,steps:[
        {type:"intro",title:"Niet & Geen",desc:"Dutch has TWO words for negation: 'niet' (not) and 'geen' (no/not a). One simple rule covers 90% of cases.",goals:["niet = not (for verbs, adjectives, adverbs)","geen = not a / no (replaces een)","Place negation correctly","Stop mixing them up"]},
        {type:"teach",trg:"niet",src:"not",pos:"intj",gender:null,phonetic:"neet",note:"Negates verbs and adjectives.\nGoes AFTER the verb: 'Ik woon niet in Amsterdam.'",example:"A: Ben je Nederlands?\nB: Nee, ik ben niet Nederlands.\nA: Waar kom je vandaan?",exampleSrc:"A: Are you Dutch?\nB: No, I am not Dutch.\nA: Where are you from?",funFact:"Germanic cousin of English 'not', German 'nicht'."},
        {type:"teach",trg:"geen",src:"no / not a / not any",pos:"intj",gender:null,phonetic:"gayn",note:"Replaces 'een' (a/an) to negate nouns.\n'Ik heb een auto' → 'Ik heb geen auto.'",example:"A: Heb je een auto?\nB: Nee, ik heb geen auto.\nA: Ik ook niet!",exampleSrc:"A: Do you have a car?\nB: No, I don't have a car.\nA: Me neither!",funFact:"Germanic cousin of German 'kein'."},
        {type:"tip",title:"⚡ The Golden Rule: Niet vs Geen",deepDive:{
          title:"Where does 'niet' go in the sentence?",
          text:"Placement of 'niet' follows these patterns:\n\nAfter the verb:\nIk zwem niet. = I don't swim.\n\nBefore adjectives:\nHet is niet groot. = It's not big.\n\nBefore prepositional phrases:\nIk woon niet in Amsterdam. = I don't live in Amsterdam.\n\nAt the end if nothing else:\nIk weet het niet. = I don't know.\n\nCommon beginner mistake:\n❌ Ik niet woon in Amsterdam.\n✅ Ik woon niet in Amsterdam.\n\nThe verb stays in position 2. 'Niet' comes after it."
        },text:"Would you use 'een' (a/an) in the positive sentence?\n\n✅ YES → use GEEN:\n• Ik heb een hond → Ik heb GEEN hond.\n• Dat is een probleem → Dat is GEEN probleem.\n\n❌ NO → use NIET:\n• Ik ben groot → Ik ben NIET groot.\n• Hij woont in Utrecht → Hij woont NIET in Utrecht.\n\nOne rule, 90% of cases."},
        {type:"teach",trg:"ik ben niet...",src:"I am not...",pos:"verb",gender:null,phonetic:"ik ben neet",note:"Niet AFTER 'ben', BEFORE adjective.\n'Ik ben niet groot, niet klein...'",example:"A: Ben je ziek?\nB: Nee, ik ben niet ziek. Ik ben moe.\nA: Ga dan slapen!",exampleSrc:"A: Are you sick?\nB: No, I am not sick. I am tired.\nA: Then go to sleep!",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"ik heb geen...",src:"I don't have (a)...",pos:"verb",gender:null,phonetic:"ik hep gayn",note:"'Geen' goes where 'een' would go.\ngeen tijd, geen geld, geen probleem!",example:"A: Heb je tijd?\nB: Sorry, ik heb geen tijd.\nA: Dat is jammer.",exampleSrc:"A: Do you have time?\nB: Sorry, I don't have time.\nA: That's a shame.",funFact:"Dutch verbs follow the stem + ending pattern. Find the stem, add the right ending."},
        {type:"teach",trg:"dat is geen probleem",src:"that's no problem",pos:"intj",gender:null,phonetic:"daht is gayn pro-BLAYM",note:"One of the most useful Dutch phrases.\nYou'll say this ten times a day.",example:"A: Sorry, ik ben laat!\nB: Dat is geen probleem!\nA: Dank je, je bent aardig.",exampleSrc:"A: Sorry, I'm late!\nB: That's no problem!\nA: Thanks, you're kind.",funFact:"Dutch and English are the closest major language pair in the world. Many words share common roots."},
        {type:"tip",title:"🔁 Niet & Geen with Zijn + Hebben",text:"ZIJN + niet:\nIk ben niet Nederlands. = I'm not Dutch.\nHij is niet hier. = He is not here.\n\nHEBBEN + geen:\nIk heb geen geld. = I have no money.\nWij hebben geen kinderen. = We don't have children.\n\nPattern: zijn pairs with 'niet', hebben pairs with 'geen'."},
        {type:"mc",q:"'Ik heb ___ auto.' (I don't have a car.)",opts:["geen","niet","nee","ja"],ans:"geen",hint:"Would the positive use 'een'? Ik heb een auto → ..."},
        {type:"mc",q:"'Hij is ___ groot.' (He is not tall.)",opts:["geen","niet","nee","un"],ans:"niet",hint:"Negating an adjective"},
        {type:"fb",opts:["geen","niet","nee","de"],hint:"No problem! (negating a noun)",s:"Dat is ___ probleem!",a:"geen"},
        {type:"mc",q:"Which sentence is CORRECT?",opts:["Ik niet woon in Amsterdam.","Niet ik woon in Amsterdam.","Ik woon niet in Amsterdam.","Ik woon in niet Amsterdam."],ans:"Ik woon niet in Amsterdam.",hint:"Verb stays in position 2, ___ comes after"},
        {type:"mc",q:"'Wij hebben geen kinderen' means:",opts:["We have children","We want children","We like children","We don't have children"],ans:"We don't have children",hint:"Geen = no / not any"},
        {type:"match",pairs:[{trg:"niet",src:"not (verbs/adjectives)"},{trg:"geen",src:"no / not a (nouns)"},{trg:"geen probleem",src:"no problem"},{trg:"niet hier",src:"not here"}]}
  ]},
  {id:"v2u1l10",title:"Unit 1 Review",icon:"🔄",xp:25,board:true,steps:[
        {type:"intro",title:"Unit 1: Everything Together",desc:"Time to prove you own this. No new words, just L1–L9 mixed together. If you nail this, you're ready for Unit 2.",goals:["Greetings & goodbyes","All forms of zijn & hebben","Questions, articles, negation","Polite phrases & introductions"]},
        {type:"tip",title:"📋 What You Know Now",text:"After 9 lessons you can:\n\n• Greet anyone (formal + casual)\n• Say goodbye four different ways\n• Say all forms of zijn and hebben\n• Ask who, what, where, how, when, why\n• Use de, het, and een correctly\n• Be polite (alsjeblieft, dank je)\n• Count to ten\n• Introduce yourself naturally\n• Say 'no' with niet and geen\n\nThat's a LOT for Unit 1. Let's test it."},
        {type:"mc",q:"It's 3 PM. You enter a shop. You say:",opts:["Goedemiddag","Goedemorgen","Goedenavond","Doei"],ans:"Goedemiddag",hint:"Afternoon greeting"},
        {type:"mc",q:"'Wij ___ blij.', Fill in the verb (to be):",opts:["ben","zijn","is","bent"],ans:"zijn",hint:"Which form of 'to be' fits plural subjects?"},
        {type:"fb",opts:["Waar","Wie","Wat","Hoe"],hint:"Asking for a location",s:"___ is het station?",a:"Waar"},
        {type:"mc",q:"Which noun uses 'het'?",opts:["man","vrouw","kind","kat"],ans:"kind",hint:"One of the het-words from L4"},
        {type:"mc",q:"In a question, 'jij hebt' becomes:",opts:["Hebt jij?","Hebben jij?","Heeft jij?","Heb jij?"],ans:"Heb jij?",hint:"Inversion causes the -t to disappear from the verb form"},
        {type:"fb",opts:["Sorry","Hallo","Dank je","Dag"],hint:"Excusing yourself before speaking",s:"___, ik spreek een beetje Nederlands.",a:"Sorry"},
        {type:"verb_table",title:"Zijn: to be",note:"4 forms: ben, bent, is, zijn.",groups:[
          {
            label:"Singular",
            rows:[{pronoun:"ik",form:"ben",src:"I am"},{pronoun:"jij / je",form:"bent",src:"you are"},{pronoun:"u",form:"bent",src:"you are (formal)"}]
          },
          {label:"He / She / It",rows:[{pronoun:"hij / zij / het",form:"is",src:"he / she / it is"}]},
          {label:"Plural",rows:[{pronoun:"wij / jullie / zij",form:"zijn",src:"we / you all / they are"}]}
        ],label:"Review"},
        {type:"verb_table",title:"Hebben: to have",note:"4 forms: heb, hebt, heeft, hebben.",groups:[
          {
            label:"Singular",
            rows:[{pronoun:"ik",form:"heb",src:"I have"},{pronoun:"jij / je",form:"hebt",src:"you have"},{pronoun:"u",form:"heeft",src:"you have (formal)"}]
          },
          {label:"He / She / It",rows:[{pronoun:"hij / zij / het",form:"heeft",src:"he / she / it has"}]},
          {label:"Plural",rows:[{pronoun:"wij / jullie / zij",form:"hebben",src:"we / you all / they have"}]}
        ],label:"Review"},
        {type:"mc",q:"'Zij ___ een huis.' (They ___ a house.)",opts:["hebben","bent","heeft","is"],ans:"hebben",hint:"Which form of 'to have' fits plural subjects?"},
        {type:"mc",q:"You hand someone their change. You say:",opts:["Dank je","Alsjeblieft","Sorry","Dag"],ans:"Alsjeblieft",hint:"'Here you go!'"},
        {type:"mc",q:"'Ik heb ___ geld.' (I don't have money.)",opts:["niet","nee","geen","een"],ans:"geen",hint:"Negating a noun: would use 'een' in positive?"},
        {type:"fb",opts:["kom","ben","heb","heet"],hint:"Stating where you're from",s:"Ik ___ uit Nederland.",a:"kom"},
        {type:"mc",q:"How do you say 'seven' in Dutch?",opts:["zes","vijf","negen","zeven"],ans:"zeven",hint:"Sounds like 'ZAY-vun'"},
        {type:"match",pairs:[{trg:"hoe heet je?",src:"what's your name?"},{trg:"waar woon je?",src:"where do you live?"},{trg:"geen probleem",src:"no problem"},{trg:"dank je wel",src:"thank you very much"}]},
        {type:"mc",q:"'Aangenaam' is used when:",opts:["Meeting someone","Saying goodbye","Ordering food","Apologizing"],ans:"Meeting someone",hint:"Nice to meet you"},
        {type:"mc",q:"Which greeting uses the Dutch throat 'g' sound?",opts:["alsjeblieft","goedemorgen","tot ziens","aangenaam"],ans:"goedemorgen",hint:"Goede... starts with 'g'"},
        {type:"mc",q:"Which is CORRECT?",opts:["Ik ben niet student.","Ik niet ben student.","Ik ben geen student.","Ik geen ben student."],ans:"Ik ben geen student.",hint:"___ has an implied 'een': so use ___"}
  ,{type:"match",pairs:[{trg:"tot later",src:"see you later"},{trg:"een boek",src:"a book"},{trg:"acht",src:"eight"},{trg:"maar",src:"but"}]}]},
  {id:"v2u1l11",title:"Reactiewoorden",icon:"💬",xp:20,board:true,steps:[
        {type:"intro",title:"Reactiewoorden: Response Words",desc:"These seven words show up in almost every Dutch conversation. Master them and your dialogues will sound natural immediately.",goals:["aardig: nice/kind","snel: fast/quickly","geweldig: great/awesome","punt: point","keuze: choice","klinken: to sound","kloppen: to be correct"]},
        {type:"teach",trg:"aardig",src:"nice / kind",pos:"adj",gender:null,phonetic:"AHR-dug",note:"One of the most common Dutch adjectives.\nUsed for people and gestures.\n'Wat aardig van je!' = How kind of you!",example:"A: Dank je voor de hulp!\nB: Graag gedaan.\nA: Je bent heel aardig.",exampleSrc:"A: Thanks for the help!\nB: You're welcome.\nA: You are very kind.",funFact:"Related to 'aard' (nature/character). An 'aardig' person has a good nature, a good character."},
        {type:"teach",trg:"snel",src:"fast / quickly",pos:"adj",gender:null,phonetic:"snel",note:"Works as both adjective and adverb.\n'Een snelle auto' = a fast car.\n'Hij loopt snel.' = He walks quickly.",example:"A: Jullie zijn laat!\nB: Sorry, de tijd gaat snel!\nA: Volgende keer sneller.",exampleSrc:"A: You are late!\nB: Sorry, time goes fast!\nA: Quicker next time.",funFact:"Germanic cousin of English 'snail' (which moves slowly, the opposite of snel). The Dutch word went in the fast direction."},
        {type:"teach",trg:"geweldig",src:"great / awesome / wonderful",pos:"adj",gender:null,phonetic:"guh-VEL-dug",note:"Strong approval, stronger than 'goed' or 'leuk'.\nUsed for achievements, experiences, people.\n'Geweldig gedaan!' = Fantastic job!",example:"A: Ik spreek nu een beetje Nederlands!\nB: Dat is geweldig!\nA: Dank je!",exampleSrc:"A: I speak a little Dutch now!\nB: That's awesome!\nA: Thanks!",funFact:"From 'geweld' (force/power). Something 'geweldig' is so good it hits you with force. Dutch uses physical metaphors for intensity."},
        {type:"teach",trg:"het punt",src:"the point",pos:"noun",gender:"n",phonetic:"hut punt",note:"Het-word. Plural: punten.\nThree daily uses:\n1. A point (in discussion): 'Goed punt!'\n2. A dot/period (punctuation)\n3. A score (in a game)",example:"A: We moeten vroeg zijn.\nB: Goed punt!\nA: Ja, de tijd gaat snel.",exampleSrc:"A: We need to be on time.\nB: Good point!\nA: Yes, time goes fast.",funFact:"Cognate with English 'point', German 'Punkt'. All from Latin 'punctum' (a prick, a dot)."},
        {type:"teach",trg:"de keuze",src:"the choice",pos:"noun",gender:"c",phonetic:"duh KUH-zuh",note:"De-word. Plural: keuzes.\n'Goede keuze!' = Good choice!\n'Een keuze maken' = to make a choice.",example:"A: Koffie of thee?\nB: Koffie, alsjeblieft.\nA: Dat is een goede keuze!",exampleSrc:"A: Coffee or tea?\nB: Coffee, please.\nA: That's a good choice!",funFact:"From 'kiezen' (to choose). The suffix -e turns the verb into a noun. Same pattern: kies (verb stem) + e = keuze."},
        {type:"teach",trg:"klinken",src:"to sound",pos:"verb",gender:null,phonetic:"KLING-kun",note:"Regular verb. Stam = klink.\n'Dat klinkt leuk!' = That sounds fun!\n'Klinkt goed!' = Sounds good! (the most Dutch way to agree)",example:"A: Zullen we morgen fietsen?\nB: Dat klinkt leuk!\nA: Tot morgen dan!",exampleSrc:"A: Shall we go cycling tomorrow?\nB: That sounds fun!\nA: See you tomorrow then!",funFact:"Germanic cousin of English 'clink' and German 'klingen'. Onomatopoeic root, the sound a glass makes."},
        {type:"teach",trg:"kloppen",src:"to knock / to be correct",pos:"verb",gender:null,phonetic:"KLOP-pun",note:"Two meanings:\n1. To knock on a door: 'Ik klop op de deur.'\n2. To be correct/right: 'Dat klopt!' = That's right!\nMeaning 2 is by far more common in conversations.",example:"A: Jij bent student, toch?\nB: Ja, dat klopt!\nA: Ik ook.",exampleSrc:"A: You're a student, right?\nB: Yes, that's right!\nA: Me too.",funFact:"The 'right' meaning comes from accounts tallying (kloppen) correctly. When numbers matched, the books 'klopt'. Now used for any truth."},
        {type:"tip",title:"💬 The Four Response Lines",text:"You'll hear these in every Dutch conversation:\n\n'Dat klopt!' = That's right! / Correct!\n'Dat klinkt leuk/goed!' = That sounds fun/good!\n'Goed punt!' = Good point!\n'Goede keuze!' = Good choice!\n\nEach one makes you sound natural immediately.\nDutch people use them constantly as acknowledgements."},
        {type:"mc",q:"'Dat klinkt leuk!' means:",opts:["That looks nice!","That sounds fun!","That feels good!","That tastes great!"],ans:"That sounds fun!",hint:"Klinken = to s..."},
        {type:"mc",q:"'Dat klopt' is used when:",opts:["Something sounds good","Something is correct","Something is a good choice","Something is funny"],ans:"Something is correct",hint:"From accounting: books that 'tally'"},
        {type:"fb",opts:["keuze","punt","geweldig","aardig"],hint:"Confirming a good decision",s:"Koffie? Dat is een goede ___!",a:"keuze"},
        {type:"mc",q:"'Je bent heel aardig' means:",opts:["You are very fast","You are very nice","You are very busy","You are very tall"],ans:"You are very nice",hint:"Aardig = n..."},
        {type:"match",pairs:[{trg:"geweldig",src:"great/awesome"},{trg:"aardig",src:"nice/kind"},{trg:"snel",src:"fast/quickly"},{trg:"het punt",src:"the point"},{trg:"klinken",src:"to sound (auditory)"},{trg:"kloppen",src:"to be correct / to knock"}]},
        {type:"fb",opts:["geweldig","aardig","snel","klopt"],hint:"Strong approval: better than 'leuk'",s:"Je spreekt heel goed Nederlands! Dat is ___!",a:"geweldig"},
        {type:"fb",opts:["klinkt","is","wordt","heeft"],hint:"Use the verb for auditory impression: 'that ___ fun'. Third-person singular form.",s:"Zullen we morgen fietsen? Dat ___ leuk!",a:"klinkt"},
        {type:"fb",opts:["klopt","werkt","past","gaat"],hint:"Used to confirm a fact. From the accounting verb meaning the books tally.",s:"Jij bent student, toch? Ja, dat ___!",a:"klopt"}
  ]}
]};
